using System.ComponentModel;
using System.Net.Http;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public sealed class ExternalApiTool
{
    [McpServerTool, Description("Fetches data from an external API for the given resource path.")]
    public static async Task<string> FetchData(
        IHttpClientFactory httpClientFactory,
        [Description("The API resource path to query (e.g. /users/1)")] string path,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync(path, cancellationToken);
        response.EnsureSuccessStatusCode();
        return await response.Content.ReadAsStringAsync(cancellationToken);
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public sealed class SummarizePrompt
{
    [McpServerPrompt, Description("Generates a prompt to summarize the provided text.")]
    public static IList<McpServerPromptMessage> Summarize(
        [Description("The text content to summarize")] string text,
        [Description("Optional desired summary style (e.g. bullet-points, one-paragraph)")] string? style = null)
    {
        var systemInstruction = style is not null
            ? $"Summarize the following text in {style} style. Be concise and capture key points."
            : "Summarize the following text concisely, capturing the key points.";

        return
        [
            new McpServerPromptMessage
            {
                Role = Role.User,
                Content = new Content { Text = $"{systemInstruction}\n\n{text}" }
            }
        ];
    }
}

